local pR={}
function pR.named(hv)
    assert(type(hv)=="string","Symbols must be created using a string name!")
    local self=newproxy(true)
    local r_=("Symbol(%s)"):format(hv)
    getmetatable(self).__tostring=function()
        return r_
    end
    return self
end
return pR
